import java.util.Scanner;
import org.owasp.encoder.Encode;

public class XSSFixedCode {

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String name = scanner.nextLine();

        // Encode user input before outputting it
        String encodedName = Encode.forHtml(name);
        System.out.println("Hello, " + encodedName + "!");

        // Malicious script embedded in the output
        String maliciousScript = "<script>alert('XSS Vulnerability')</script>";
        // Encode the malicious script before outputting it
        String encodedScript = Encode.forHtml(maliciousScript);
        System.out.println(encodedScript); // This will be displayed as text without executing the script
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
